from decimal import Decimal, InvalidOperation, ROUND_HALF_EVEN

def parse_edad_monto(edad_txt: str, monto_txt: str) -> dict:
    raw = {"edad": edad_txt, "monto": monto_txt}
    clean = {"edad": None, "monto": None}
    errors: list[str] = []

    t = edad_txt.strip()
    if t == "":
        errors.append(f"ERROR en 'edad': vacío (raw={edad_txt!r})")
    else:
        try:
            clean["edad"] = int(t)
        except ValueError:
            errors.append(f"ERROR en 'edad': no es entero (raw={edad_txt!r})")

    m = monto_txt.strip()
    if m == "":
        errors.append(f"ERROR en 'monto': vacío (raw={monto_txt!r})")
    else:
        try:
            clean["monto"] = Decimal(m).quantize(Decimal("0.01"), rounding=ROUND_HALF_EVEN)
        except InvalidOperation:
            errors.append(f"ERROR en 'monto': no es decimal (raw={monto_txt!r})")

    return {"raw": raw, "clean": clean, "errors": errors}

for a, b in [("34", "150.50"), ("abc", "20.00"), ("21", "xx")]:
    print(parse_edad_monto(a, b))

