def parse_client(nombres, apellido_paterno, apellido_materno, contacto, direccion, edad=None):
    errors = []
    out = {
        "nombres_raw": nombres,
        "apellido_paterno_raw": apellido_paterno,
        "apellido_materno_raw": apellido_materno,
        "contacto_raw": contacto,
        "direccion_raw": direccion,
        "edad_raw": edad,
    }
    def clean_str(campo, val):
        t = val.strip()
        if not t:
            errors.append(f"ERROR en '{campo}': vacío (raw={val!r})")
            return None
        return t
    out["nombres"] = clean_str("nombres", nombres)
    out["apellido_paterno"] = clean_str("apellido_paterno", apellido_paterno)
    out["apellido_materno"] = clean_str("apellido_materno", apellido_materno)
    out["contacto"] = clean_str("contacto", contacto)
    out["direccion"] = clean_str("direccion", direccion)
    if edad is None:
        out["edad"] = None
    else:
        ok, n, err = safe_int("edad", edad)
        out["edad"] = n
        if err:
            errors.append(err)
    out["errors"] = errors
    return out

